import boto3
import json

def process_message(message):
    try:
        message_body = json.loads(message['Body'])
        message_type = message_body.get('type')

        if message_type == 'type1':
            # Handle type1 message
            handle_type1(message_body)
        elif message_type == 'type2':
            # Handle type2 message
            handle_type2(message_body)
        else:
            raise ValueError(f"Unknown message type: {message_type}")

    except json.JSONDecodeError as e:
        print(f"Failed to decode JSON message: {e}")
    except KeyError as e:
        print(f"Missing key in message body: {e}")
    except Exception as e:
        print(f"Error processing message: {e}")

